const crossSellMap = {
  'mowing':        ['fertilization', 'aeration'],
  'lawn mowing':   ['fertilization', 'aeration'],
  'fertilization': ['aeration', 'herbicide'],
  'aeration':      ['fertilization', 'mulching'],
  'herbicide':     ['fertilization', 'aeration'],
  'spring-cleanup':['mulching', 'fertilization'],
  'spring cleanup':['mulching', 'fertilization'],
  'fall-cleanup':  ['leaf-removal', 'gutter-cleaning'],
  'fall cleanup':  ['leaf-removal', 'gutter-cleaning'],
  'leaf-removal':  ['gutter-cleaning', 'fall-cleanup'],
  'leaf removal':  ['gutter-cleaning', 'fall-cleanup'],
  'gutter-cleaning':['gutter-guards', 'fall-cleanup'],
  'gutter cleaning':['gutter-guards', 'fall-cleanup'],
  'mulching':      ['garden-bed-care', 'bush-trimming'],
  'garden-bed-care':['mulching', 'bush-trimming'],
  'bush-trimming': ['mulching', 'garden-bed-care'],
  'bush trimming': ['mulching', 'garden-bed-care'],
  'snow-removal':  ['spring-cleanup', 'gutter-cleaning'],
  'snow removal':  ['spring-cleanup', 'gutter-cleaning'],
  'hardscaping':   ['mulching', 'garden-bed-care']
};

const formatService = (s) => s.replace(/[-_]/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

const FONT = "-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif";
const GREEN = '#2D5A27';
const GOLD = '#C5A55A';
const DARK = '#1a1a2e';

function buildCrossSellHtml(name, currentService, rec1, rec2) {
  const cs = formatService(currentService);
  const r1 = formatService(rec1);
  const r2 = formatService(rec2);
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background:#f4f4f4;font-family:${FONT};">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f4;"><tr><td align="center" style="padding:20px 0;">
<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06);">
<!-- Header -->
<tr><td style="background:${GREEN};padding:16px 24px;"><table width="100%" cellpadding="0" cellspacing="0"><tr><td style="font-size:18px;font-weight:700;color:#fff;">TotalGuard Yard Care</td><td align="right" style="font-size:14px;"><a href="tel:+16085356057" style="color:#fff;text-decoration:none;font-weight:600;">(608) 535-6057</a></td></tr></table></td></tr>
<!-- Body -->
<tr><td style="padding:32px 32px 16px;"><h1 style="margin:0 0 16px;font-size:22px;color:${GREEN};line-height:1.3;">Get Even More From Your Property</h1><p style="margin:0 0 20px;font-size:15px;color:#333;line-height:1.7;">Hi ${name},</p><p style="margin:0 0 20px;font-size:15px;color:#333;line-height:1.7;">You already trust us with <strong>${cs}</strong> &mdash; here's how to get even more from your property. Based on what we know about your yard, we think you'd love these services:</p></td></tr>
<!-- Recommendations -->
<tr><td style="padding:0 32px 16px;"><table width="100%" cellpadding="0" cellspacing="0" style="background:#f0f8f0;border:2px solid ${GREEN};border-radius:8px;"><tr><td style="padding:20px 24px;"><p style="margin:0 0 4px;font-size:11px;color:${GOLD};text-transform:uppercase;letter-spacing:2px;font-weight:700;">RECOMMENDED FOR YOU</p><p style="margin:8px 0 4px;font-size:16px;font-weight:700;color:${GREEN};">&bull; ${r1}</p><p style="margin:4px 0;font-size:16px;font-weight:700;color:${GREEN};">&bull; ${r2}</p></td></tr></table></td></tr>
<!-- CTA -->
<tr><td style="padding:16px 32px 24px;" align="center"><table cellpadding="0" cellspacing="0" style="width:100%;"><tr><td align="center" style="border-radius:6px;background:${GREEN};"><a href="https://tgyardcare.com/contact?utm_source=email&utm_medium=cross-sell&utm_campaign=tg10" style="display:block;padding:16px 32px;font-size:16px;font-weight:700;color:#fff;text-decoration:none;border-radius:6px;text-align:center;">Add a Service</a></td></tr></table></td></tr>
<!-- Trust Bar -->
<tr><td style="padding:0 32px 24px;"><table width="100%" cellpadding="0" cellspacing="0" style="background:${GREEN};border-radius:6px;"><tr><td align="center" style="padding:14px 16px;font-size:12px;color:#fff;line-height:2;">&#10003; Licensed &amp; Insured &bull; &#10003; 4.9&#9733; Rating &bull; &#10003; 500+ Properties</td></tr></table></td></tr>
<!-- Footer -->
<tr><td style="background:${DARK};border-radius:0 0 8px 8px;padding:24px 32px;text-align:center;"><p style="margin:0 0 8px;font-size:16px;font-weight:700;color:#fff;">TotalGuard Yard Care</p><p style="margin:0 0 8px;font-size:13px;color:#999;">7610 Welton Dr, Madison, WI 53711 &bull; <a href="tel:+16085356057" style="color:${GOLD};text-decoration:none;">(608) 535-6057</a></p><p style="margin:8px 0 0;font-size:11px;color:#666;">You're receiving this because you're a TotalGuard customer. <a href="https://tgyardcare.com/unsubscribe" style="color:#999;text-decoration:underline;">Unsubscribe</a></p></td></tr>
</table></td></tr></table></body></html>`;
}

const customers = $input.all().map(i => i.json);
const results = [];
let sent = 0;

for (const c of customers) {
  if (!c.email || !c.service) continue;
  const svc = (c.service || '').toLowerCase().trim();
  const recs = crossSellMap[svc] || ['fertilization', 'aeration'];
  const rec1 = recs[0];
  const rec2 = recs[1] || recs[0];
  const firstName = c.first_name || 'there';
  const subject = `${firstName}, have you tried ${formatService(rec1)}?`;
  const html_body = buildCrossSellHtml(firstName, c.service, rec1, rec2);

  results.push({
    json: {
      to_email: c.email,
      subject: subject,
      html_body: html_body,
      workflow_name: 'TG-10',
      email_type: 'cross_sell'
    }
  });
  sent++;
}

if (results.length === 0) {
  return [{ json: { _skip: true, reason: 'No eligible customers', _sent_count: 0 } }];
}

// Append count to last item for Telegram
results[results.length - 1].json._sent_count = sent;
return results;

